member.example:
Bind the CapsuleCollider radius property using a serialized binder field — the target CapsuleCollider is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private CapsuleColliderRadiusBinder _radius;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _radius;
    }


Bind the CapsuleCollider radius property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private CapsuleCollider _capsuleCollider;
        
        private CapsuleColliderRadiusBinder Radius =>
            new(_capsuleCollider);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _radius;
    }

Switch the CapsuleCollider radius between two float values using a serialized binder field — the target CapsuleCollider is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private CapsuleColliderRadiusSwitcherBinder _isExpanded;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isExpanded;
    }


Switch the CapsuleCollider radius between two float values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private CapsuleCollider _capsuleCollider;
        
        private CapsuleColliderRadiusSwitcherBinder IsExpanded => new(
            _capsuleCollider,
            trueValue: 1f,
            falseValue: 0.5f);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isExpanded;
    }
